#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, m, a[10010], flag, fl;
bool f[10010];
void dfs(int s)
{
	if (fl)return;
	if (s > n)
	{
		flag++;
		if (flag == m + 1)
		{
			for (int j = 1; j <= n; ++j)cout << a[j] << ' ';
			fl = 1;
		}
		return;
	}
	for (int i = 1; i <= n; ++i)
	{
		if (flag == 0)i = a[s];
		if (f[i] == 0)
		{
			f[i] = 1;
			a[s] = i;
			dfs(s + 1);
			f[i] = 0;
		}
	}
}
int main(void)
{
	cin >> n >> m;
	for (int i = 1; i <= n; ++i)cin >> a[i];
	dfs(1);
	return false;
}
